exercises.solution_code:
#include <iostream>

int main()
{
    int a{};
    int b{};
    std::cin >> a >> b;

    int* ptr{ new int{ a + b } };
    std::cout << *ptr << '\n';

    delete ptr;
    ptr = nullptr;

    std::cout << (ptr == nullptr ? "nullptr" : "dangling") << '\n';

    return 0;
}

