exercises.solution_code:
#include <iostream>

int main()
{
    int x{};
    int y{};
    std::cin >> x >> y;

    int* ptrX{ new int{ x } };
    int* ptrY{ new int{ y } };

    int temp{ *ptrX };
    *ptrX = *ptrY;
    *ptrY = temp;

    std::cout << *ptrX << '\n';
    std::cout << *ptrY << '\n';

    delete ptrX;
    delete ptrY;
    ptrX = nullptr;
    ptrY = nullptr;

    if (ptrX == nullptr && ptrY == nullptr)
        std::cout << "clean" << '\n';

    return 0;
}
